parameters.text:
={{
  String(
    $node["Agente de Segurança Suíça"].json.output
    ?? $json.output
    ?? $json.text
    ?? ""
  )
  .replace(/\n?This message was sent automatically with n8n\s*$/i, "")
  .trim()
}}

parameters.jsCode:
// ===== AMIG / Protectas - Pré-triagem (STABLE + SAFE) =====

const msg = $json?.message ?? $json ?? {};

// texto pode vir como text/caption/userText (depende do tipo de msg e do teu fluxo)
const rawText =
  msg.text ??
  msg.caption ??
  $json.text ??
  $json.userText ??
  "";

// sessionId para memória (Simple Memory)
const sessionId = String(
  msg?.chat?.id ??
  $json?.chat?.id ??
  $json?.message?.chat?.id ??
  "fallback"
);

return [{
  json: {
    ...$json,
    text: rawText,
    userText: rawText,
    sessionId
  }
}];
